import React, { useState } from 'react'
import { Card, Rate, Skeleton, Tooltip } from 'antd';
import { EyeFilled, HeartFilled, PlusOutlined } from '@ant-design/icons';
import { TProduct } from '../../Layout/app/Types';
import { Currency } from '../../Layout/app/Const';

const CardProduct = (data:[TProduct]) => {

  const [loading, setLoading] = useState<boolean>(false);

  return (

    data?.map((item,index)=>{
      return(
        <div key={index} className='Card_Product'>
        <Skeleton className='unset' loading={loading} active avatar>
      <Card className='unset' loading={loading}>
        <div className='Card_Product_Top'>
          <span className='Left'> {item?.off}% off </span>
          <span className='Right'> <EyeFilled/> <HeartFilled/> </span>
        </div>
        <div className='Card_Product_Mid'>
        <img src={"../Product/Product_1.png"} alt='Error' width="100%" height="60%" />

        </div>
        <div className='Card_Product_Bottom'>
          <div>{item?.name}</div>
          <div> <Rate allowHalf disabled defaultValue={item?.rate} /> </div>
          <span>
            <div>
            <strong>{item?.off} {Currency}</strong>
            <small> 250{Currency}  </small>
            </div>
            <div className='AddProduct'>
            <Tooltip title="Add To Card">
            <PlusOutlined/>
  </Tooltip>
            </div>
            </span>
        </div>
        </Card>
      </Skeleton>

    </div>
      )
    })

  )
}

export default CardProduct
